  ('generalpolice-8b7f1efc-moex-00269', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-112-3a7b2121', 'sub-generalpolice-8b7f1efc-06', NULL, 'single_choice', '下列何者對於公共利益的解讀較符合經濟學的觀點？ 社區成員對於共同社會需求的滿足  社會資源最高效率使用及最佳配置 社會組織發揮其功能所產生的利益  為消除衝突所產生的相互依賴關係', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:35+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00270', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-112-3a7b2121', 'sub-generalpolice-8b7f1efc-06', NULL, 'single_choice', '有關萬斯來（G. L. Wamsley）等人於《黑堡宣言》中提出的「政府與美國人民對話」（Government and the American Dialogue），下列敘述何者錯誤？ 美國有必要將政府的角色重新聚焦於「行政」的性質與角色上 行政應聚焦於如何限縮政府的功能 重申行政擁有管理技能的核心，政治系絡中也有運用這些技能的傳承經驗 美國政府面臨諸多的治理難題，罪魁禍首多數不在於行政機關，但後果卻由行政機關來扛', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:35+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00271', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-112-3a7b2121', 'sub-generalpolice-8b7f1efc-06', NULL, 'single_choice', '行政院成立國家永續發展委員會，負責國家永續發展相關業務的決策，這和下列何種理念關聯性 較高？ 新公共管理  新公共行政  歐盟統合  全球考量，在地行動', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:35+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL)
